// === src/components/Navbar.js ===
import React from 'react';
import { Link } from 'react-router-dom';
import './Navbar.css';

const Navbar = () => {
  const user = JSON.parse(localStorage.getItem('currentUser'));

  const handleLogout = () => {
    localStorage.removeItem('currentUser');
    window.location.href = '/';
  };

  return (
    <nav className="navbar">
      <h1 className="logo">Paradise Nursery</h1>
      <ul className="nav-links">
        <li><Link to="/">Home</Link></li>
        {user && <li><Link to="/shop">Shop</Link></li>}
        {user && <li><Link to="/cart">Cart</Link></li>}
        {user && <li><Link to="/checkout">Checkout</Link></li>}
        {user?.isAdmin && <li><Link to="/admin">Admin</Link></li>}
        {user?.isAdmin && <li><Link to="/orders">Orders</Link></li>}
      </ul>
      <div className="user-section">
        {user ? (
          <>
            <span className="user-label">{user.isAdmin ? 'Admin' : 'User'}</span>
            <button onClick={handleLogout} className="logout-btn">Logout</button>
          </>
        ) : (
          <Link to="/login" className="login-btn">Login</Link>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
